import{_ as o,o as r,c as a,a2 as i}from"./chunks/framework.DnrXFDHb.js";const c=JSON.parse('{"title":"🫘 黃豆追蹤日報 — 2026-05-19（週二）","description":"","frontmatter":{},"headers":[],"relativePath":"Deep32Q知識庫/產業洞察/黃豆研究/追蹤日誌/黃豆追蹤_2026-05-19.md","filePath":"Deep32Q知識庫/產業洞察/黃豆研究/追蹤日誌/黃豆追蹤_2026-05-19.md"}'),l={name:"Deep32Q知識庫/產業洞察/黃豆研究/追蹤日誌/黃豆追蹤_2026-05-19.md"};function n(s,t,e,d,g,h){return r(),a("div",null,[...t[0]||(t[0]=[i('<h1 id="🫘-黃豆追蹤日報-—-2026-05-19-週二" tabindex="-1">🫘 黃豆追蹤日報 — 2026-05-19（週二） <a class="header-anchor" href="#🫘-黃豆追蹤日報-—-2026-05-19-週二" aria-label="Permalink to &quot;🫘 黃豆追蹤日報 — 2026-05-19（週二）&quot;">​</a></h1><blockquote><p>查詢時間：2026-05-19 05:00 TST（2026-05-18 21:00 UTC） 報告類型：每日追蹤 ⚠️ CBOT 期貨時段說明：05:00 TST 週二凌晨 = 17:00 ET 週一，黃豆期貨已收盤</p></blockquote><hr><h2 id="📊-即時報價" tabindex="-1">📊 即時報價 <a class="header-anchor" href="#📊-即時報價" aria-label="Permalink to &quot;📊 即時報價&quot;">​</a></h2><table tabindex="0"><thead><tr><th>指標</th><th>報價</th><th>日漲跌</th><th>查詢時間</th><th>來源</th></tr></thead><tbody><tr><td>CBOT 黃豆 Jul 2026 (ZS=F)</td><td>1,212 USd/Bu</td><td>+35¢ (+2.97%)</td><td>2026-05-18 16:00 ET</td><td>TradingEconomics</td></tr><tr><td>WTI 原油</td><td>$108.66/桶</td><td>+$3.24 (+3.08%)</td><td>2026-05-18</td><td>TradingEconomics</td></tr><tr><td>Brent 原油</td><td>$112.10/桶</td><td>+$2.84 (+2.60%)</td><td>2026-05-18</td><td>TradingEconomics</td></tr><tr><td>DXY 美元指數</td><td>98.98</td><td>-0.29 (-0.30%)</td><td>2026-05-18</td><td>TradingEconomics</td></tr><tr><td>天然氣 Henry Hub</td><td>$2.96/MMBtu</td><td>—</td><td>2026-05-15</td><td>TradingEconomics</td></tr></tbody></table><blockquote><p><strong>查詢時間（TST）</strong>：2026-05-19 05:00</p></blockquote><hr><h2 id="🔍-敘事延續-川習會-17b-農業承諾-川普叫停伊朗攻擊-—-黃豆反彈-2-97" tabindex="-1">🔍 敘事延續：川習會 $17B 農業承諾 + 川普叫停伊朗攻擊 — 黃豆反彈 2.97% <a class="header-anchor" href="#🔍-敘事延續-川習會-17b-農業承諾-川普叫停伊朗攻擊-—-黃豆反彈-2-97" aria-label="Permalink to &quot;🔍 敘事延續：川習會 $17B 農業承諾 + 川普叫停伊朗攻擊 — 黃豆反彈 2.97%&quot;">​</a></h2><p><strong>本日核心</strong>：CBOT 黃豆 Jul 反彈至 1,212 USd/Bu（+2.97%），從上週五 1,177¢ 大幅回升。驅動因素雙重：① White House 公布川習會事實清單，中國承諾 2026-2028 每年購買 $17B 美國農產品（含黃豆）；② 川普叫停伊朗攻擊，油價從日高 $112+ 回落，能源成本壓力短暫紓解。USDA 種植進度 48% 領先五年均值 36%。巴西 StoneX 下修至 177.8M 噸（乾旱），但 CONAB 180.13M 噸仍為歷史紀錄。</p><hr><h2 id="_8-項追蹤指標" tabindex="-1">8 項追蹤指標 <a class="header-anchor" href="#_8-項追蹤指標" aria-label="Permalink to &quot;8 項追蹤指標&quot;">​</a></h2><h3 id="_1-usda-種植進度報告-每週" tabindex="-1">1. USDA 種植進度報告（每週） <a class="header-anchor" href="#_1-usda-種植進度報告-每週" aria-label="Permalink to &quot;1. USDA 種植進度報告（每週）&quot;">​</a></h3><ul><li><strong>種植進度</strong>（截至 5/11）：48% 黃豆已播種（前週 33%），高於五年均值 36%</li><li><strong>出芽率</strong>：待下週更新（截至 5/4 為 13%，五年均值 5%）</li><li><strong>個別州</strong>：Illinois 57%、Iowa 60%、Indiana 51%（前週數據）</li><li><strong>WASDE 5/12</strong>：2026/27 終庫存 310M bu（低於預期 ~355M），壓榨 2.75B bu（連續 6 年創紀錄）</li><li><strong>變化</strong>：🟡 種植進度持續領先 — 下週 expected 55%+ 播種</li><li><strong>查詢時間</strong>：2026-05-18</li><li>來源：Farm Progress (2026-05-12)、RFD TV (2026-05-15)、USSEC (2026-05)</li></ul><h3 id="_2-巴西供應-收割-出口-豐收" tabindex="-1">2. 巴西供應（收割 + 出口 + 豐收） <a class="header-anchor" href="#_2-巴西供應-收割-出口-豐收" aria-label="Permalink to &quot;2. 巴西供應（收割 + 出口 + 豐收）&quot;">​</a></h3><ul><li><strong>CONAB</strong>（5 月）：2025/26 產量 180.13M 噸（+0.5% vs 前估，+5% YoY）</li><li><strong>StoneX</strong>（5 月）：下修至 177.8M 噸（從 181.6M），南大河乾旱</li><li><strong>出口</strong>：CONAB 預測 116M 噸（+7.25% YoY）</li><li><strong>2026/27 展望</strong>：USDA 預估巴西產量 186M 噸（+8M vs 本季）</li><li><strong>變化</strong>：🟡 無重大變化 — 本季已收割完成，關注下季播種</li><li><strong>查詢時間</strong>：2026-05-18</li><li>來源：CONAB (2026-05)、StoneX/Biofuels Digest (2026-05)</li></ul><h3 id="_3-尿素價格-多單訊號" tabindex="-1">3. 尿素價格 + 多單訊號 <a class="header-anchor" href="#_3-尿素價格-多單訊號" aria-label="Permalink to &quot;3. 尿素價格 + 多單訊號&quot;">​</a></h3><ul><li><strong>尿素</strong>：$577/噸（+0.79%），月跌 19.07% 但年漲 21.79%</li><li><strong>荷莫茲效應</strong>：全球 ~30% 化肥出口經過海峽，成本持續高檔</li><li><strong>變化</strong>：🟡 成本高檔但月跌 — 短期壓力紓解但長期結構性上升</li><li><strong>查詢時間</strong>：2026-05-15</li><li>來源：TradingEconomics (2026-05-15)</li></ul><h3 id="_4-荷莫茲海峽通航狀態" tabindex="-1">4. 荷莫茲海峽通航狀態 <a class="header-anchor" href="#_4-荷莫茲海峽通航狀態" aria-label="Permalink to &quot;4. 荷莫茲海峽通航狀態&quot;">​</a></h3><ul><li>🔴 <strong>持續惡化但出現轉機信號</strong>：</li><li><strong>川普叫停攻擊</strong>（5/18）：原訂週二攻擊被叫停，因沙烏地/卡達/阿聯酋請求「hold off」</li><li><strong>伊朗提案</strong>（Axios 5/18）：提交新版提案——海峽重開換停火，核談判推遲</li><li><strong>白宮回應</strong>：認為伊朗 offer 不足</li><li><strong>Al Jazeera</strong>：三艘美國驅逐艦在交火中通過海峽</li><li><strong>CENTCOM</strong>：70+ 艘商業船被改道，4 艘被扣押</li><li><strong>對黃豆影響</strong>：叫停攻擊 → 能源成本短暫紓解 → 農業成本壓力緩和 → 支撐黃豆反彈</li><li><strong>變化</strong>：🟡 <strong>轉機信號出現但未實質改善</strong> — 叫停攻擊≠重開海峽</li><li><strong>查詢時間</strong>：2026-05-18</li><li>來源：CNBC (2026-05-18)、Axios (2026-05-18)、Al Jazeera (2026-05-18)</li></ul><h3 id="_5-中美貿易-中國進口" tabindex="-1">5. 中美貿易 + 中國進口 <a class="header-anchor" href="#_5-中美貿易-中國進口" aria-label="Permalink to &quot;5. 中美貿易 + 中國進口&quot;">​</a></h3><ul><li>🔴 <strong>關鍵進展</strong>：White House 公布事實清單，中國承諾 $17B/年農產品</li><li><strong>White House</strong>（5/17）：中國承諾 2026-2028 每年購買 $17B 美國農產品</li><li><strong>中國商務部</strong>（5/16）：定性為「preliminary」，需「finalised as soon as possible」</li><li><strong>S&amp;P Global</strong>：年初至今美國對華黃豆銷售年減 48%</li><li><strong>分析</strong>：$17B 承諾是正面信號，但「preliminary」+ 9-10 月收成季時間壓力</li><li><strong>變化</strong>：🟡 延續前次 — 承諾已公布但尚未落實</li><li><strong>查詢時間</strong>：2026-05-18</li><li>來源：White House (2026-05)、SCMP (2026-05-16)、S&amp;P Global (2026-05-14)</li></ul><h3 id="_6-天然氣價格" tabindex="-1">6. 天然氣價格 <a class="header-anchor" href="#_6-天然氣價格" aria-label="Permalink to &quot;6. 天然氣價格&quot;">​</a></h3><ul><li><strong>Henry Hub</strong>：$2.96/MMBtu（+2.28%），接近七週高</li><li><strong>EIA 注入</strong>：85 bcf（符合預期），低於去年同期 109 bcf</li><li><strong>變化</strong>：🟡 無重大變化 — 供給偏緊但需求季節性低</li><li><strong>查詢時間</strong>：2026-05-15</li><li>來源：TradingEconomics (2026-05-15)、AGA (2026-05-15)</li></ul><h3 id="_7-聖嬰-拉尼娜氣候風險" tabindex="-1">7. 聖嬰/拉尼娜氣候風險 <a class="header-anchor" href="#_7-聖嬰-拉尼娜氣候風險" aria-label="Permalink to &quot;7. 聖嬰/拉尼娜氣候風險&quot;">​</a></h3><ul><li><strong>變化</strong>：⚪ 本日無重大更新 — 待下季氣候報告</li><li><strong>查詢時間</strong>：2026-05-19</li></ul><h3 id="_8-cbot-價格區間-海運成本" tabindex="-1">8. CBOT 價格區間 + 海運成本 <a class="header-anchor" href="#_8-cbot-價格區間-海運成本" aria-label="Permalink to &quot;8. CBOT 價格區間 + 海運成本&quot;">​</a></h3><ul><li><strong>Jul 2026</strong>：1,212 USd/Bu（+2.97%），從 1,177¢ 反彈</li><li><strong>技術面</strong>：從 1,177¢ 反彈，挑戰 1,220¢ 壓力位，支撐 1,180-1,200¢</li><li><strong>變化</strong>：🟢 <strong>反彈</strong> — 川習會農業承諾 + 叫停攻擊雙重利多</li><li><strong>查詢時間</strong>：2026-05-18</li><li>來源：TradingEconomics (2026-05-18)</li></ul><hr><h2 id="📰-即時新聞-5-條" tabindex="-1">📰 即時新聞（5 條） <a class="header-anchor" href="#📰-即時新聞-5-條" aria-label="Permalink to &quot;📰 即時新聞（5 條）&quot;">​</a></h2><ol><li><strong>TradingEconomics (2026-05-18)</strong>：Soybeans rose to 1,212 USd/Bu, up 2.97%, rebounding on China $17B ag commitment</li><li><strong>CNBC (2026-05-18)</strong>：Trump calls off Iran attack, oil volatile but stays elevated at $108.66</li><li><strong>Axios (2026-05-18)</strong>：Iran submits updated peace proposal — Hormuz reopening for ceasefire, nuclear talks postponed</li><li><strong>Farm Progress (2026-05-12)</strong>：USDA soybean planting 48% through May 11, ahead of 36% five-year average</li><li><strong>White House (2026-05)</strong>：China commits $17B/year in US ag purchases through 2028</li></ol><hr><h2 id="📊-情景分析" tabindex="-1">📊 情景分析 <a class="header-anchor" href="#📊-情景分析" aria-label="Permalink to &quot;📊 情景分析&quot;">​</a></h2><table tabindex="0"><thead><tr><th>情境</th><th>發生機率</th><th>價格影響</th><th>傳導機制</th></tr></thead><tbody><tr><td>中國 6 月下調關稅 + $17B 實際執行 + 海峽局部重開</td><td>35%</td><td>+8-12%（至 ~1,300-1,360¢）</td><td>需求大增 + 能源成本下降</td></tr><tr><td>海峽持續封閉 + 叫停攻擊只是暫緩</td><td>45%</td><td>持平至 -2%（1,180-1,220¢）</td><td>能源成本高檔支撐 vs 需求疲軟</td></tr><tr><td>中國延遲關稅下調 + 巴西下季播種因乾旱延遲</td><td>25%</td><td>+3-5%（至 ~1,250-1,270¢）</td><td>全球供應擔憂 + 投機買盤</td></tr></tbody></table><hr><h2 id="📚-資料來源" tabindex="-1">📚 資料來源 <a class="header-anchor" href="#📚-資料來源" aria-label="Permalink to &quot;📚 資料來源&quot;">​</a></h2><ol><li>TradingEconomics (2026-05-18): Soybeans 1,212, WTI $108.66, DXY 98.98</li><li>White House (2026-05): Fact sheet — China commits $17B/year in US ag purchases</li><li>CNBC (2026-05-18): Trump calls off Iran attack, markets volatile</li><li>Axios (2026-05-18): Iran submits updated peace proposal</li><li>Farm Progress (2026-05-12): USDA crop progress 48% planted</li><li>CONAB (2026-05): Brazil soybean production 180.13M tons</li><li>StoneX/Biofuels Digest (2026-05): Brazil harvest cut to 177.8M tons</li><li>S&amp;P Global (2026-05-14): US soybean sales to China fall 48% YTD</li><li>SCMP (2026-05-16): China-US farm deal scope analysis</li><li>USSEC (2026-05): US soybean planting progress 23% → 48%</li></ol>',36)])])}const b=o(l,[["render",n]]);export{c as __pageData,b as default};
